from typing import Any, List

class BagInterface:
    def __init__(self):
        self.bag = []

    def insert(self, item: Any):
        self.bag.append(item)

    def contains(self, item: Any) -> bool:
        return item in self.bag

    def count(self, item: Any) -> int:
        return self.bag.count(item)

    def remove(self, item: Any):
        self.bag.remove(item)

    def clear(self):
        self.bag = []

    def size(self) -> int:
        return len(self.bag)

    def is_empty(self) -> bool:
        return len(self.bag) == 0

    def is_full(self) -> bool:
        return len(self.bag) == 20


class PlainBag(BagInterface):
    def __init__(self):
        super().__init__()


class MagicChangeBag(BagInterface):
    def __init__(self):
        super().__init__()

    def insert(self, item: Any):
        pass

    def remove(self, item: Any):
        self.bag = [item]
```

In the above implementation, the BagInterface class serves as an abstract class defining the common operations for both PlainBag and MagicChangeBag classes. The PlainBag class uses a simple array implementation to hold the items, while the MagicChangeBag class overrides the insert method to make the item magically disappear and the remove method to make all items except the one to be removed appear.

Note that in the MagicChangeBag class, we are assigning the bag to a list containing only the item to be removed when the remove method is called. This makes the bag look empty except for the item to be removed.

