```cpp
#include <iostream>
#include <algorithm>
#include <vector>

using namespace std;

template<typename T>
class BagInterface {
public:
    virtual void insert(T item) = 0;

    virtual bool contains(T item) = 0;

    virtual int count(T item) = 0;

    virtual void remove(T item) = 0;

    virtual void clear() = 0;

    virtual int size() = 0;

    virtual bool is_empty() = 0;

    virtual bool is_full() = 0;
};


template<typename T>
class PlainBag : public BagInterface<T> {
private:
    vector<T> bag;

public:
    void insert(T item) override {
        bag.push_back(item);
    }

    bool contains(T item) override {
        return find(bag.begin(), bag.end(), item) != bag.end();
    }

    int count(T item) override {
        return count(bag.begin(), bag.end(), item);
    }

    void remove(T item) override {
        bag.erase(remove(bag.begin(), bag.end(), item), bag.end());
    }

    void clear() override {
        bag.clear();
    }

    int size() override {
        return bag.size();
    }

    bool is_empty() override {
        return bag.empty();
    }

    bool is_full() override {
        return bag.size() == 20;
    }
};


template<typename T>
class MagicChangeBag : public BagInterface<T> {
private:
    vector<T> bag;

public:
    void insert(T item) override {
        // Item magically disappears, do nothing
    }

    bool contains(T item) override {
        return false;  // Bag always appears empty
    }

    int count(T item) override {
        return 0;  // Bag always appears empty
    }

    void remove(T item) override {
        bag.clear();
        bag.push_back(item);
    }

    void clear() override {
        bag.clear();
    }

    int size() override {
        return bag.size();
    }

    bool is_empty() override {
        return bag.empty();
    }

    bool is_full() override {
        return bag.size() == 20;
    }
};

int main() {
    PlainBag<int> bag1;
    bag1.insert(1);
    bag1.insert(2);
    bag1.insert(3);

    cout << "PlainBag Contents: ";
    while (!bag1.is_empty()) {
        int item = bag1.size();
        cout << item << " ";
        bag1.remove(item);
    }
    cout << endl;

    MagicChangeBag<int> bag2;
    bag2.insert(1);
    bag2.insert(2);
    bag2.insert(3);

    cout << "MagicChangeBag Contents: ";
    while (!bag2.is_empty()) {
        int item = bag2.size();
        cout << item << " ";
        bag2.remove(item);
    }
    cout << endl;

    return 0;
}
```

